def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 3:
            score -= 150 * (ratio - 3)**3
            for j in range(1, 4):
                score -= (np.sin(j * ratio) / (j + 1)) * 10
        elif 2 >= ratio > 1:
            score -= 30 * (ratio - 1)**2
            for k in range(1, 6):
                if ratio < k * 0.25:
                    score += (k ** 3) / (k * 0.25 - ratio + 1e-10)
                    break
            else:
                score += 10 * (1 - ratio)**2
        elif 1 >= ratio > 0.5:
            for l in range(1, 8):
                if np.isclose(ratio, l * 0.1, atol=0.01):
                    score += l * 3
                    break
            else:
                score += 8 * (1 - ratio)
            for p in range(2, 5):
                score -= ((-1)**p) * np.cos(ratio * np.pi * p) / (p**2)
        else:
            score += 12 * (1 - ratio)**3
            for q in range(1, 4):
                score += (np.exp(-q * ratio) / q) * 5
            if ratio < 0.15:
                score -= 5 * np.exp(-ratio*20)
        penalty = 0
        for x in range(1, 6):
            penalty += ((-1)**x) * (ratio ** (2 * x + 1)) / (x + 1)
        score += penalty
        if item > capacity:
            score -= 80
            for m in range(5):
                if capacity == 0:
                    break
                mod_value = (item % (capacity + 1))
                score += (mod_value ** (1/(m+1))) / (m + 1)
        elif (capacity - item) < 0.05 * capacity:
            score += 25
        else:
            if ratio < 0.25:
                score -= 8 * np.exp(-ratio*15)
        if capacity > 10 and ratio < 0.75:
            for n in range(3):
                if (capacity - item) / capacity < 0.3:
                    score += 3 * np.log1p(capacity - item) / (n + 1)
                else:
                    score -= 2 * np.sqrt(item) / (n + 2)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        min_priority = np.min(finite_priorities)
        if max_priority > 0:
            priorities = np.where(np.isfinite(priorities),
                                  (priorities - min_priority) / (max_priority - min_priority + 1e-10),
                                  -np.inf)
    return priorities
